'use client';

import React, { useEffect } from 'react';
import Link from 'next/link';
import { usePathname, useRouter } from 'next/navigation';
import { useAuth } from '../../lib/auth';
import styles from './layout.module.css';

export default function AdminLayout({ children }: { children: React.ReactNode }) {
  const { user, isAdmin, loading, logout } = useAuth();
  const router = useRouter();
  const pathname = usePathname();

  useEffect(() => {
    if (!loading && (!user || !isAdmin)) {
      router.push('/');
    }
  }, [user, isAdmin, loading, router]);

  if (loading) {
    return <div className={styles.loadingContainer}>Checking administration credentials...</div>;
  }

  if (!user || !isAdmin) {
    return <div className={styles.loadingContainer}>Access Denied. Redirecting to catalog...</div>;
  }

  const navLinks = [
    { href: '/admin/orders', label: 'Order Inbox & Revenue' },
    { href: '/admin/stock', label: 'Stock & Product Manager' },
    { href: '/admin/wholesalers', label: 'Wholesaler Manager' },
  ];

  return (
    <div className={styles.adminContainer}>
      {/* Top Navbar */}
      <header className="glass-nav">
        <div className={styles.navContainer}>
          <div className={styles.leftNav}>
            <Link href="/" className={styles.logo}>
              Stokiloo<span>.</span>
            </Link>
            <span className={styles.divider}>/</span>
            <span className={styles.pageTitle}>Admin Dashboard</span>
          </div>

          <div className={styles.navActions}>
            <span className={styles.adminEmail}>{user.email} (Admin)</span>
            <Link href="/" className="btn btn-secondary">
              View Catalog
            </Link>
            <button className="btn btn-secondary" onClick={logout}>
              Sign Out
            </button>
          </div>
        </div>
      </header>

      {/* Main Admin Layout */}
      <div className={`container ${styles.layoutBody}`}>
        {/* Sidebar Nav */}
        <aside className={styles.sidebar}>
          <nav className={styles.navMenu}>
            {navLinks.map((link) => {
              const isActive = pathname === link.href;
              return (
                <Link
                  key={link.href}
                  href={link.href}
                  className={`${styles.navItem} ${isActive ? styles.active : ''}`}
                >
                  {link.label}
                </Link>
              );
            })}
          </nav>
        </aside>

        {/* Dynamic Route Content */}
        <main className={styles.mainContent}>{children}</main>
      </div>
    </div>
  );
}
